    curlioerr err;

    Curl_set_in_callback(data, true);
    err = (data->set.ioctl_func)(data, CURLIOCMD_RESTARTREAD,
                                 data->set.ioctl_client);
    Curl_set_in_callback(data, false);
    DEBUGF(infof(data, "cr_in, rewind via set.ioctl_func -> %d", (int)err));
